package com.ichi2.anki.cardviewer

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.RobolectricTest
import org.intellij.lang.annotations.Language
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Tests for TypeAnswer with useInputTag enabled
 * 
 * This verifies the fix for the bug where answer comparison was not shown
 * when "Type answer into the card" advanced option is enabled
 */
@RunWith(AndroidJUnit4::class)
class TypeAnswerInputTagTest : RobolectricTest() {
    override fun setUp() {
        super.setUp()
        col
    }

    @Test
    fun testFilterAnswerWithInputTagEnabled() {
        @Language("HTML")
        val answerTemplate = """<style>.card {
 font-family: arial;
 font-size: 20px;
 text-align: center;
}
</style>Type in hello
[[type:Back]]

<hr id=answer>

hello"""

        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Simulate user typing "hello" correctly
        typeAnswer.input = "hello"
        val resultCorrect = typeAnswer.filterAnswer(answerTemplate, "hello", "hello")

        // Should show comparison with correct answer
        assertTrue("Should contain comparison with typeGood class", 
            resultCorrect.contains("typeGood"))

        // Simulate user typing incorrect answer
        typeAnswer.input = "world"
        val resultIncorrect = typeAnswer.filterAnswer(answerTemplate, "world", "hello")

        // Should show comparison with incorrect answer
        assertTrue("Should contain comparison with typeBad class",
            resultIncorrect.contains("typeBad"))
        assertTrue("Should contain comparison with typeMissed class",
            resultIncorrect.contains("typeMissed"))
    }

    @Test
    fun testFilterAnswerWithEmptyInput() {
        @Language("HTML")
        val answerTemplate = """Type in hello
[[type:Back]]

hello"""

        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Simulate no input (empty string)
        typeAnswer.input = ""
        val result = typeAnswer.filterAnswer(answerTemplate, "", "hello")

        // Should show just the correct answer without comparison styling
        assertTrue("Should contain the correct answer", result.contains("hello"))
        // When input is empty, no comparison classes should be present
        assertTrue("Should contain typeans code element", result.contains("code id=typeans"))
    }

    @Test
    fun testFilterQuestionWithInputTag() {
        @Language("HTML")
        val questionTemplate = """Type in the answer:
[[type:Back]]"""

        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        val result = typeAnswer.filterQuestion(questionTemplate)

        // Should contain HTML input tag
        assertTrue("Should contain input element", result.contains("<input"))
        assertTrue("Should contain id=\"typeans\"", result.contains("id=\"typeans\""))
        assertTrue("Should contain onblur handler", result.contains("onblur="))
        assertTrue("Should contain onKeyPress handler", result.contains("onKeyPress="))
    }
}
"}

